const { Toast, Modal, restUrl } = jui,
  { jsx } = vanillaSignal,
  { t } = vanillaSignalI18n,
  { createQuery } = vanillaSignalQuery,
  langs = {
    zh: {
      Login: '登录',
      username: '用户名',
      password: '密码',
      Cancel: '取消',
      'Enter Username Please': '请输入用户名',
      'Enter Password Please': '请输入密码',
      'Username Required': '用户名不能为空',
      'Password Required': '密码不能为空',
      'Login Success': '登录成功',
    },
  },
  ts = (e) => t(e, langs),
  performLogin = async (e, a) => {
    const s = await fetch(restUrl + '/api/v1/auth/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username: e, password: a }),
    });
    return s.json();
  },
  createLoginMutation = (e) =>
    createQuery({
      queryKey: ['login', e.username],
      queryFn: async () => await performLogin(e.username, e.password),
      enabled: !1,
      cache: !1,
      retry: 0,
      throwErrors: !0,
    }),
  loginModal = new Modal({
    title: ts('Login'),
    confirmText: ts('Login'),
    cancelText: ts('Cancel'),
    escClose: !0,
    fields: [
      {
        label: ts('username'),
        type: 'text',
        name: 'username',
        id: 'username',
        placeholder: ts('Enter Username Please'),
        required: !0,
      },
      {
        label: ts('password'),
        type: 'password',
        name: 'password',
        id: 'password',
        placeholder: ts('Enter Password Please'),
        required: !0,
      },
    ],
    onSubmit: async (e) => {
      if (e.username.trim())
        if (e.password.trim()) {
          loginModal.state.loading = !0;
          try {
            const a = createLoginMutation({
                username: e.username,
                password: e.password,
              }),
              s = await a.refetch({ force: !0 });
            (200 === s.code
              ? (Toast.success(ts('Login Success')),
                setTimeout(() => {
                  window.location.href = '/';
                }, 1e3))
              : Toast.error(s.message),
              (loginModal.state.loading = !1));
          } catch (e) {
            (Toast.error(e.message || 'Login Failed'),
              (loginModal.state.loading = !1));
          }
        } else Toast.error(ts('Password Required'));
      else Toast.error(ts('Username Required'));
    },
  });
document.body.addEventListener('click', (e) => {
  e.target.closest('[data-action="login"]') && loginModal.show();
});
